<script setup lang="ts">import{ref,watch}from"vue";import{desktopApi}from"../../shared/api";import{errorMessage}from"../../shared/errors";import type{ConfigItemDto,GitStatusDto}from"../../shared/bindings";const props=defineProps<{repository:string}>();const configs=ref<ConfigItemDto[]>([]);const git=ref<GitStatusDto>();const error=ref("");async function refresh(){try{[configs.value,git.value]=await Promise.all([desktopApi.listConfigs(props.repository),desktopApi.gitStatus(props.repository)]);}catch(e){error.value=errorMessage(e);}}watch(()=>props.repository,refresh,{immediate:true});</script>
<template><section class="panel overview"><header class="panel-header"><div><p class="eyebrow">环境总览</p><h1>迁移状态</h1></div></header><p v-if="error" class="notice warning">{{error}}</p><div class="overview-cards"><article><small>配置项</small><strong>{{configs.length}}</strong><span>{{configs.filter(v=>v.status==='modified').length}} 项有差异</span></article><article><small>Git 工作区</small><strong>{{git?.changed.length??'—'}}</strong><span>{{git?.branch??'等待加载'}}</span></article><article><small>安全策略</small><strong>开启</strong><span>原子写入 · 自动备份</span></article></div><div class="overview-guide"><h2>推荐迁移流程</h2><ol><li>添加配置文件并检查本机/仓库差异</li><li>扫描软件包并保存期望清单</li><li>提交变更，设置远程后推送</li><li>新设备克隆仓库，先预览再应用和安装</li></ol></div></section></template>
